var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"唔？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"엘릭서의 효력을 최대한 끌어올렸는데도 버티는 게 한계라니.","JPN":"エリクサーの効力を最大限まで引き上げたのに、凌ぐのがやっとだなんて。","ENG":"I maximized the effects of the Elixir, and yet, I am barely able to stand on my two feet.","TWN":"在將聖水的效果發揮到極致的情況下也撐得很勉強呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"부상을 입고도 어떻게 저런 힘이…?!","JPN":"ボロボロの身体で、いったいどうやってここまでを力を……！？","ENG":"How can she be so powerful even with all those wounds...?!","TWN":"為什麼傷成那樣力氣還…？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"내가 널 중용하지 않는 것이 마음에 들지 않느냐?","JPN":"私がお前を重用視しないことが不満か？","ENG":"Are you displeased with my not using you?","TWN":"你在生氣我沒有重用你嗎？"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"이유를 알고 싶습니다. 제가 임무를 보다 완벽하게 해내지 못했기 때문입니까?","JPN":"理由を知りたいのです。私の任務遂行がより完璧になれば良いのでしょうか？","ENG":"I wish to know why. Was it because I could not execute my missions with perfection?","TWN":"我想知道原因，是因為我辦事不力嗎？"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"너는 내가 거두기 전부터 누구보다 차가운 심장을 가지고 있었다.","JPN":"お前は私が引き取る以前から、誰よりも冷たい心を持っておった。","ENG":"Your heart was colder than anyone's since before I took you in.","TWN":"在我收留你之前，你的心就已經比任何人都還要冷酷。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"어쩌면, 널 다스릴 수 있는 건 흑동이 가르치는 냉철함이 아닐 지도 모른다는 생각이 들더구나.","JPN":"もしかすると、お前を導けるのは黒東が持つ冷徹さではないかと思っておる。","ENG":"It struck my mind that Black East's teachings of ruthlessness might not be enough to control you.","TWN":"我就想，或許能夠管束你的，不是黑東所教導的冷血。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"저에겐 사부님의 가르침이 전부입니다.","JPN":"私は師匠からの教えしか欲しくありません。","ENG":"Your teachings are everything to me, master.","TWN":"對我來說，師父的教導就是一切。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니, 어떻게 해야 하는지 가르쳐주십시오.","JPN":"ですから、どうすれば良いか教えてください。","ENG":"So please, instruct me on what to do.","TWN":"所以，請告訴我，我該怎麼辦。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"너에게 이름을 주마.","JPN":"ではお前に名前を授けよう。","ENG":"I shall give you a name.","TWN":"我要給你名字。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"이것이 내 마지막 가르침이니, 잘 간직하거라.","JPN":"これは私の最後の教えだ。大事にするといい。","ENG":"Cherish it, as it will be my last teaching.","TWN":"這是我最後的教導，你要收好它。"},"stage":{"bg":"CLAN","bgm":"THEMA_CIEL","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘!","JPN":"シエルさん！","ENG":"Ciel!","TWN":"希爾！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…학생회장?","JPN":"……生徒会長？","ENG":"...Ms. President?","TWN":"…學生會長？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 이상 계속하면, 그 자는 죽습니다.","JPN":"それ以上続けると、その者は死んでしまいます。","ENG":"He will die if you continue.","TWN":"你再不住手的話他會死的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"쿨럭…","JPN":"がはっ……","ENG":"*Cough...*","TWN":"呃…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인의 손에 묻은 것이… 이 자의 피요?","JPN":"自分の手についているのは……この者の血なのですか？","ENG":"This stain on my hands... Is it this man's blood?","TWN":"在下手上的血…是他的嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"설마…? 방금 무슨 일이 있었는지 기억나지 않는 건가요?","JPN":"まさか……？　何が起きたか、覚えていないのですか？","ENG":"What...? Do you not remember what just happened?","TWN":"你…？不記得剛才發生什麼事嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"모르겠소.","JPN":"わかりません。","ENG":"I do not.","TWN":"不記得。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러고보니… 예전에도 이것과 비슷한 일을 겪었던 것 같구려.","JPN":"そういえば……以前も同じようなことがあった気がします。","ENG":"Upon reflection... I believe I have had a similar experience once before.","TWN":"不過在下想起… 之前好像也有過類似的情況。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하… 하하… 의식도 없는 상대에게 사경까지 내몰리다니. 없는 체면 다 구겼구만.","JPN":"は……はは……意識のない相手に殺されかけるとは。こりゃ名が廃れるぜ。","ENG":"Ha... Haha... Beaten to a pulp by someone who was unconscious... I've lost face.","TWN":"哈…哈哈…竟然被沒有意識的對手逼到絕境，真是丟人。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"으읏…?!","JPN":"ううっ……！？","ENG":"Ugh...?!","TWN":"呃呃…？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘? 괜찮나요?","JPN":"シエルさん？　大丈夫ですか？","ENG":"Ciel! Are you all right?","TWN":"希爾？你還好嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"다리에 힘이 풀렸소.","JPN":"足の力が抜けてしまいました。","ENG":"My legs have failed me.","TWN":"雙腿無力，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"뿐만 아니라… 팔도 움직일 수가 없구려.","JPN":"それだけでなく……腕も動きません。","ENG":"It is not just my legs... I cannot move my arms either.","TWN":"手臂也…動不了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무래도 방금까지 사용한 힘에 반작용이 있는 것 같네요.","JPN":"どうやら意識のない状態で使っていた力の反動のようですね。","ENG":"It must be a reaction to the power you just used.","TWN":"應該是剛才用力過度的副作用。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"걱정 말아요. 제가 부축할 테니.","JPN":"大丈夫です。私が支えます。","ENG":"Rest assured. I will help you up.","TWN":"沒事，我來扶你。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이 소린…?","JPN":"この音は……？","ENG":"This sound...","TWN":"這聲音是…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스가 너무 늦지 않게 도착한 모양이군요.","JPN":"イーディスが間に合ってくれたみたいですね。","ENG":"Edith seems to have arrived just in time.","TWN":"伊蒂絲及時抵達的樣子。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"이런 젠장! 도대체 어디서 미사일이 쏟아지는 거야!","JPN":"くそぉ！　このミサイルはいったいどこから降ってきているんだ！","ENG":"Dammit! Where are all these missiles coming from?!","TWN":"該死！導彈到底是從哪冒出來的！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"부사관! 본대가 위험에 처했다! 실험체는 어찌돼도 상관없으니 돌아와서 이쪽을 지원해!","JPN":"下士官！　本隊が危ないぞ！　実験体などもうどうでもいい、とりあえずこっちを支援しろ！","ENG":"Sergeant! The main forces are under fire! Abandon the test subject and come cover us!","TWN":"副官！我們遇到危險！別管實驗體了，快回來支援這裡！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"죄송하지만 지휘관님, 저도 붙잡혔습니다.","JPN":"申し訳ございません、指揮官。僕も捕まってしまいました。","ENG":"I'm sorry, Commander. I've also been caught.","TWN":"指揮官很抱歉，我現在也自身難保。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"뭐라고?! 이런 쓸모없는…!","JPN":"何だと！？　この役立たずが……！","ENG":"What?! You useless little...!","TWN":"你說什麼？！你這沒用的東…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아직 움직일 여력은 있어 보이는데, 저항하지 않는 건가요?","JPN":"まだ動けそうに見えますが、抵抗しないのですか？","ENG":"You seem like you can still move. Will you not resist?","TWN":"我看你似乎還能動，不反抗嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"됐어. 지금은 한숨 돌리자고.","JPN":"もういい。一旦休戦しようぜ。","ENG":"No. Let me rest a little.","TWN":"不了，我要先喘口氣。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"시엘 양을 갖는 데엔 실패했지만… 그래도 소기의 목적은 달성했으니까.","JPN":"シエルは手に入れられなかったけど……元来の目的は達成したからな。","ENG":"I may have failed in obtaining Ciel... but I did accomplish a different goal.","TWN":"雖然沒能帶走希爾…不過至少有達到預定的目標。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"소기의 목적?","JPN":"元来の目的？","ENG":"A different goal?","TWN":"預定的目標？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"너희를 이용해서 거슬리는 상사 해치우기.","JPN":"お前たちを利用して、気に食わない上司を消すこと。","ENG":"Using you to get rid of my pesky boss.","TWN":"就是利用你們除掉礙眼的長官。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"납치할 때 이 애가 가진 휴대폰- 위치추적이 안되게 막아 뒀다고 거짓말했거든.","JPN":"拉致するとき、この子の携帯のGPSをブロックしておいたって嘘をついたんだ。","ENG":"I lied to him when we kidnapped Ciel... that I blocked all GPS signals from her phone.","TWN":"綁架希爾時，我騙他們說已經關掉她的手機定位系統。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"당신처럼 살인도 꺼리지 않는 자가 그런 번거로운 방법을 쓸 필요 있었나요?","JPN":"あなたのように殺人もいとわないような方が、そんな煩わしい方法を取ったのはどうしてでしょうか？","ENG":"What was the point of all this cumbersomeness when you feel no pang of guilt from murder?","TWN":"像你這種殺人不眨眼的人，有需要這樣多此一舉嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"작전 중 사고가 아니라 반란으로 제거해버리면, 내가 지휘관 자릴 물려받지 못하잖아?","JPN":"作戦中、事故じゃなくて反逆で消してしまったら、指揮官の座が俺に渡らないだろう？","ENG":"If he gets eliminated by my rebellion and not an accident during an operation, then I wouldn't be able to take over his position.","TWN":"要是我自己出手，而不是在作戰中製造意外的話，那我怎麼有辦法坐上指揮官的位置？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"착각하지 마시죠. 당신을 순순히 풀어줄 생각은 없으니까.","JPN":"少し勘違いしているようですが、あなたをほいほいと解放するつもりはありません。","ENG":"Do not be mistaken. I have no intention of letting you off that easily.","TWN":"是不是哪裡有誤會？我並不打算放你走。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그럴 수밖에 없을걸?","JPN":"でもそうせざるを得ないよ？","ENG":"I'm sure you'll have no choice but to.","TWN":"恐怕由不得你？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"이 놀이공원엔 내가 시설들을 전부 무너트릴 만큼의 폭탄을 숨겨뒀어.","JPN":"この遊園地には、僕が全ての施設を爆破できるだけの爆弾を設置しておいた。","ENG":"I have hidden enough explosives around the vicinity to blow up everything in this amusement park.","TWN":"我已經在這裡設下足以炸毀座遊樂園的炸彈。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"…그리고 너희에겐 지켜야 할 것들이 많잖아?","JPN":"……それに、お前たちには守るべきものがたくさんあるんじゃないか？","ENG":"...Plus, you have people to rescue, no?","TWN":"…你們不是有很多需要守護的事物嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…이런!","JPN":"……はっ！","ENG":"...Oh!","TWN":"…你竟然！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무사한가요, 시엘?","JPN":"シエルさん、ご無事ですか？","ENG":"Are you all right, Ciel?","TWN":"你沒事吧，希爾？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"업어준 덕에 멀쩡하오.","JPN":"おんぶしてもらっているおかげで、平気です。","ENG":"Yes, all thanks to you.","TWN":"沒事，謝謝你揹在下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"타오는… 놓치고 말았군요.","JPN":"タオは……逃してしまいましたね。","ENG":"We have... lost Tao.","TWN":"結果…還是被浮士德給逃了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그보다, 저쪽 건물의 기반이 곧 무너질 거요.","JPN":"それより、向こう側の構造物がもうもちません。","ENG":"Now is not the time. That building's foundation is about to collapse.","TWN":"眼前的問題比較重要，那棟建築物的地基就要塌陷了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"으아아…! 전망대가 이쪽으로 쓰러진다!","JPN":"うわあ……！　展望台がこっちに倒れてくるぞ！","ENG":"Aaagh...! The observatory is falling toward us!","TWN":"啊啊啊…！觀景台正往這邊倒過來！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_03"},{"id":"L38_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"아, 안돼! 너무 빨라서 피할 수가…!","JPN":"だ、ダメだ！　速すぎて避けられ……！","ENG":"N-no! We don't have time to get to cover...!","TWN":"不，不可以！倒得太快來不及逃…！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런…!","JPN":"しまった……！","ENG":"No...!","TWN":"糟糕…！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"콜록 콜록.","JPN":"ゲホッ！　ゲホッ……！","ENG":"*Cough!* *Cough!*","TWN":"呼呼呼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"우리… 살았나?","JPN":"俺たち……生きているのか？","ENG":"We're... alive?","TWN":"我們…還活著嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"윽… 끄으으응…","JPN":"うっ……うううっ……","ENG":"Ngh... Errgh...","TWN":"呃…呃呃呃…"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나, 나이엘…?!","JPN":"な、ナイエル？","ENG":"N-Naielle...?!","TWN":"奈，奈爾…？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"야, 뭐해? ","JPN":"何ボケっとしているのよ。 ","ENG":"Hey, what are you doing?","TWN":"看什麼看！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"계속 막고 있기 힘드니까 ","JPN":"これ食い止めるの、大変なんだからね！ ","ENG":"I can't hold this for long.","TWN":"我撐得很辛苦欸！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"빨랑 옆으로 비켜!","JPN":"そこ、早くどいて！","ENG":"So move out of the way!","TWN":"還不快躲開！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"헥… 헤엑…","JPN":"はあ……ふえっ……","ENG":"*Huff...* *Huff...*","TWN":"呼…呼呼…"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나이엘… 네가 우릴 살려줬어.","JPN":"ナイエル……お前のおかげで助かった。","ENG":"Naielle... You saved our lives.","TWN":"奈爾…你救了我們。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"괜찮아? 분명 몸으로 받아내기엔 충격이 컸을 텐데…","JPN":"大丈夫か？　身体で受け止めるなんてきっと相当衝撃があったはず......","ENG":"Are you okay? I'm sure the force was too much for your body to handle...","TWN":"你沒事吧？你直接用肉身去擋會受傷吧…"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥… 뭐래? 이 A급 엘리트님께서 고작 이까짓 건물로 버거워할 리 없잖아?","JPN":"ふん……何をバカなことを言ってんの？　A級エリートにこんな建物はなんともないわよ？","ENG":"Hmph... As if. There's no way an elite Grade A like me would have trouble stopping a building from collapsing.","TWN":"哼…說什麼？我可是A級菁英，怎麼可能因為小小的建築物就受傷？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아앗! 나이엘! 너 팔이 돌아갔어!","JPN":"ああっ！　ナイエルちゃん！　腕が変な方向に曲がってるよ！","ENG":"Aack! Naielle! You dislocated your arm!","TWN":"哎呀！奈爾！你的手臂骨折咧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"엑?! 진짜?!","JPN":"えっ！？　まじ！？","ENG":"What?! Really?!","TWN":"什麼？！真的假的？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 미안. 잘못 봤네.","JPN":"あ、ごめん。勘違いだった。","ENG":"Oh, sorry, it's not. My bad.","TWN":"喔，對不起，我看錯了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어, 어쨌든. 내 덕분에 살았으니 나중에 제대로 감사나 하라고!","JPN":"と、とにかく。私に命拾いされたんだから、感謝しなさいよ！","ENG":"A-anyway. You're alive because of me, so you'd better show your appreciation!","TWN":"總，總之是我救你們一命的，之後要好好感謝我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...Okay.","TWN":"…會的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"죗값을 치르고 난 뒤엔… 반드시 보답할게.","JPN":"罪を償ったら……ちゃんと恩を返すよ。","ENG":"After we pay for our crimes... we'll make it up to you.","TWN":"等我贖完罪後…會好好報答你的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"엥…? 죗값? 너희들 무슨 죄라도 지은 거야?","JPN":"えっ……？　罪？　あんたたち、何かやらかしたの？","ENG":"Huh? Pay for your crimes? You guys did something wrong?","TWN":"什麼…？贖罪？你做了什麼壞事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"응, 우리의 별볼일 없는 욕심 때문에…","JPN":"うん、俺たちのくだらない欲望のせいで……","ENG":"Yeah, we were blinded by greed, and...","TWN":"因為我們的貪心…"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…친구를 속여서 위험에 빠트렸어.","JPN":"……友達を騙して危険な目に遭わせてしまった。","ENG":"...We deceived a friend and put her in harm's way.","TWN":"…欺騙朋友，讓她陷入危險之中。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어?! 그럼 설마, 시엘이 그렇게 다친 것도 전부 너희 때문이라는 거야?","JPN":"ええ！？　じゃあ、シエルちゃんがあんなケガをしてるのは、全てあなたたちのせいってこと？","ENG":"What?! Wait, then what happened to Ciel is all because of you?","TWN":"什麼？！所以希爾傷成那樣都是你們害的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 괜찮소.","JPN":"自分は大丈夫です。","ENG":"I am all right.","TWN":"在下沒事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"애초에 속은 것이 아니니, 그대들에게 잘못을 물을 생각은 없다오.","JPN":"そもそも騙されたわけではないので、貴殿らに責任を問うつもりはありません。","ENG":"They did not deceive me, so I do not ask that they take responsibility for it.","TWN":"在下原本就沒有受騙，因此也不打算向他們問罪。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐어- 어찌된 영문인진 모르겠지만 당사자가 괜찮다면 된 거지 뭐.","JPN":"まぁ、どうなっているのかはわからないけど、本人が大丈夫って言うなら問題ないわね。","ENG":"Well... I dunno what happened, but if she's okay with it, then I guess that's that.","TWN":"嗯嗯～雖然不清楚到底怎麼回事，但當事者都不在意的話就算囉～"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"정말… 그런 걸로 괜찮은 거야?","JPN":"本当に……それでいいのか？","ENG":"Are you... really okay with that?","TWN":"真的…沒關係嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은… 엘릭서를 받은 그대가 그 힘으로 그자와 맞서는 모습을 어렴풋이 기억하오.","JPN":"自分は……エリクサーを受け取った貴殿が、その力で彼に立ち向かったのをぼんやりと覚えているのです。","ENG":"I remember... glimpses of you taking the Elixir and using that power to fight him.","TWN":"在下依稀記得…你喝下聖水後有攻擊那個人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"하하… 정말 한심했지. 몇 초 버티지도 못했잖아.","JPN":"はは……本当に情けないよな。数秒しか持たなかったぜ。","ENG":"Haha... That was comical. I couldn't even last a few seconds.","TWN":"哈哈…我很遜吧？連幾秒都撐不住。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"허나 그 몇 초가 본인을 위험에서 구해내기엔 충분한 시간이었소.","JPN":"ですが、その数秒は自分を危険から救い出すのには十分でした。","ENG":"However, those few seconds were enough to save myself from danger.","TWN":"雖然不過幾秒，但足以證明你確實想要救在下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"하지만 고작 그런 걸로… 내가 저지른 잘못이 사라지진 않잖아.","JPN":"だけど、それだけじゃ……俺の犯した罪は消えやしない。","ENG":"But that... doesn't make what I did go away.","TWN":"就算這樣…還是無法抹滅我曾經犯下的過錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"엎지른 물 앞에 주저앉아만 있기엔, 그대들에게 아직 주어진 시간이 너무 길지 않소?","JPN":"やってしまったことを今更嘆いて、立ち止まったって仕方ありません。貴殿たちはこれから先がもっと長いのですから。","ENG":"You have time that could be better spent than crying over spilled milk.","TWN":"與其一直執著於已經犯下的錯誤，你們還有很多時間不是嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"시엘…","JPN":"シエル……","ENG":"Ciel...","TWN":"希爾…"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"우리가 너에게 진 빚을 갚을 방법이 있을까?","JPN":"俺たちに、お前への罪を償うチャンスがあるのか？","ENG":"Is there a way we can make it up to you?","TWN":"有什麼辦法可以讓我們彌補你嗎？　"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…물론이오.","JPN":"……無論です。","ENG":"Of course.","TWN":"…當然有。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대들이 멈추지만 않는다면, 앞으로도 기회는 얼마든지 있을 거요.","JPN":"貴殿らが立ち止まりさえしなければ、これからいくらでもチャンスは訪れるでしょう。","ENG":"If you do not give up, there will always be an opportunity.","TWN":"只要你們不停留在過去的錯誤裡，以後多得是機會。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};